package org.apache.commons.csv;

import static org.junit.jupiter.api.Assertions.*;
import org.junit.jupiter.api.Test;

public class CSVFormatTest {

    @Test
    public void testWithRecordSeparator_char() {
        CSVFormat original = CSVFormat.DEFAULT;
        char separator = '\n';

        CSVFormat result = original.withRecordSeparator(separator);

        assertNotNull(result);
        assertNotSame(original, result);
        assertEquals(String.valueOf(separator), result.getRecordSeparator());
    }

    @Test
    public void testWithRecordSeparator_char_differentSeparator() {
        CSVFormat original = CSVFormat.DEFAULT;
        char separator = '\r';

        CSVFormat result = original.withRecordSeparator(separator);

        assertNotNull(result);
        assertNotSame(original, result);
        assertEquals(String.valueOf(separator), result.getRecordSeparator());
    }
}
